mapper.select:
select id, order_no, customer_id, vehicle_id, pickup_time, return_time, daily_rent, total_amount,
       order_status, remark, created_by, created_at, updated_at
from rental_order


        and order_no = #{orderNo}


        and customer_id = #{customerId}


        and vehicle_id = #{vehicleId}


        and order_status = #{orderStatus}


        and pickup_time  >=  #{pickupDateStart}


        and pickup_time  <=  #{pickupDateEnd}


order by id desc
